ee:message.ee:set-payload:
%dw 2.0
output application/java

var salas = payload.data default []
---
{
  data: salas map (sala) -> {
    codigoSala: (sala.codigoSala default 0) as Number,
    nombre: (sala.nombre default "") as String,
    nivel: (sala.nivel default 0) as Number
  }
}

wsc:message.wsc:body:
#[%dw 2.0
output application/xml
ns tns http://www.example.org/ControlPresencia/
---
{
  tns#controlEmpleadosSala: {
    tns#WSKey: "SOAP-DEV-KEY-001",
    tns#in: vars.salaActualCodigo
  }
}]

#[%dw 2.0
output application/xml
ns tns http://www.example.org/Empleados/
---
{
  tns#consultarEmpleado: {
    WSKey: "SOAP-DEV-KEY-001",
    "in": vars.nifEmpleadoActual
  }
}]

ee:message.ee:set-payload:
%dw 2.0
// Conseguimos dejar al respuesta del SOAP de Empleados en una forma más limpia para tratar luego
output application/java

var out = payload.body.consultarEmpleadoResponse.out default {}
var errorSoap = payload.body.consultarEmpleadoResponse.error default null
var nif = (out.nifnie default "") as String
---
{
  data: {
    nifnie: nif,
    nombreApellidos: (out.nombreApellidos default "") as String,
    email: (out.email default "") as String,
    naf: (out.naf default "") as String,
    iban: (out.iban default "") as String,
    idNivel: (out.idNivel default 0) as Number,
    usuario: (out.usuario default "") as String,
    password: (out.password default "") as String,
    valido: ((out.valido default false) as String) == "true"
  },
  // Si el SOAP no trae out y tampoco error, lo convertimos en un error funcional nuestro en vez de clasificarlo mal como "no válido"
  error:
    if (errorSoap != null and errorSoap != "") (errorSoap as String)
    else if (nif == "") "No se ha recibido el detalle del empleado consultado"
    else null
}

set-variable.value:
#[{
  nif: (payload.data.nifnie default vars.nifEmpleadoActual default "") as String,
  // El email recibido por parámetro es al que hay que notificar sobre un usuario no válido
  email: (vars.emailDestino default "") as String,
  codigoSala: (vars.salaActualCodigo default 0) as Number,
  nombreSala: (vars.salaActualNombre default "") as String
}]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
// Necesario porque el HTTP Request REST debe enviar un JSON en el body, aquí dejamos el payload exactamente
// como el objeto que va a viajar.
vars.bodyRestEnviado

%dw 2.0
output application/java

var data = payload.data default {}
---
{
  data: {
    enviado: (data.enviado default false) as Boolean,
    detalle: (data.detalle default "") as String
  },
  error: payload.error default null
}

%dw 2.0
output application/json
---
{
  mensaje: "el proceso ha finalizado satisfactoriamente",
  resumen: {
    emailDestino: (vars.emailDestino default "") as String,
    totalSalas: (vars.totalSalas default 0) as Number,
    totalEmpleadosRevisados: (vars.totalEmpleadosRevisados default 0) as Number,
    totalNoValidosDetectados: (vars.totalNoValidos default 0) as Number,
    totalNotificacionesEnviadas: (vars.totalNotificaciones default 0) as Number
  }
}
